function calculate(inputs) {
    const {
        totalBudget,
        guestCount,
        eventDurationHours,
        eventComplexityMultiplier,
        venuePrestigeFactor,
        cateringQualityFactor,
        securityIntensityFactor,
        culturalExchangeFocusPercentage,
        contingencyPercentage
    } = inputs;

    let allocatedVenue = 0;
    let allocatedCatering = 0;
    let allocatedSecurity = 0;
    let allocatedEntertainment = 0;
    let allocatedStaffingLogistics = 0;
    let allocatedCulturalExchange = 0;
    let allocatedContingency = 0;
    let remainingBudget = 0;

    if (totalBudget <= 0) {
        return {
            allocatedVenue, allocatedCatering, allocatedSecurity, allocatedEntertainment,
            allocatedStaffingLogistics, allocatedCulturalExchange, allocatedContingency, remainingBudget: totalBudget
        };
    }

    // Ensure non-negative and reasonable factors
    const safeGuestCount = Math.max(0, guestCount);
    const safeEventDurationHours = Math.max(0.5, eventDurationHours);
    const safeComplexityMultiplier = Math.max(0.5, eventComplexityMultiplier);
    const safeVenueFactor = Math.max(0.8, venuePrestigeFactor);
    const safeCateringFactor = Math.max(0.7, cateringQualityFactor);
    const safeSecurityFactor = Math.max(0.8, securityIntensityFactor);
    const safeCulturalExchangePct = Math.min(100, Math.max(0, culturalExchangeFocusPercentage));
    const safeContingencyPct = Math.min(100, Math.max(0, contingencyPercentage));

    // 1. Allocate for Cultural Exchange first
    allocatedCulturalExchange = totalBudget * (safeCulturalExchangePct / 100);
    let budgetAfterCulturalExchange = totalBudget - allocatedCulturalExchange;
    budgetAfterCulturalExchange = Math.max(0, budgetAfterCulturalExchange);

    // Base rates for different categories (these are internal, representative values)
    const baseCateringPerGuest = 60; // Base cost per guest for catering
    const baseSecurityFixed = 1200; // Fixed security cost
    const baseSecurityPerGuest = 15; // Additional security cost per guest
    const baseEntertainmentFixed = 1800; // Fixed entertainment cost
    const baseEntertainmentPerGuest = 8; // Additional entertainment cost per guest
    const baseStaffingLogisticsFixed = 900; // Fixed staffing cost
    const baseStaffingLogisticsPerHourPerGuest = 2.5; // Hourly staffing cost per guest
    const baseVenueFixed = 3500; // Base cost for a standard venue

    // 2. Calculate initial estimates for core categories based on factors
    const estCatering = baseCateringPerGuest * safeGuestCount * safeCateringFactor;
    const estSecurity = (baseSecurityFixed + (baseSecurityPerGuest * safeGuestCount)) * safeSecurityFactor * safeComplexityMultiplier;
    const estEntertainment = (baseEntertainmentFixed + (baseEntertainmentPerGuest * safeGuestCount)) * safeComplexityMultiplier;
    const estStaffingLogistics = (baseStaffingLogisticsFixed + (baseStaffingLogisticsPerHourPerGuest * safeGuestCount * safeEventDurationHours)) * safeComplexityMultiplier;
    // Venue cost scales with prestige, guest count, and duration (more guests/longer event, more venue usage/prep)
    const estVenue = baseVenueFixed * safeVenueFactor * Math.max(1, safeGuestCount / 80) * Math.max(1, safeEventDurationHours / 3);

    const totalEstimates = estCatering + estSecurity + estEntertainment + estStaffingLogistics + estVenue;

    // 3. Allocate for Contingency
    // Contingency is based on the *remaining* budget after cultural exchange, considering the estimated core costs.
    // If core estimates exceed the budget, contingency is based on the budget available.
    const budgetForContingencyBase = Math.min(budgetAfterCulturalExchange, totalEstimates > 0 ? totalEstimates : budgetAfterCulturalExchange);
    allocatedContingency = budgetForContingencyBase * (safeContingencyPct / 100);
    let distributableBudget = budgetAfterCulturalExchange - allocatedContingency;
    distributableBudget = Math.max(0, distributableBudget);

    // 4. Proportional Allocation for core categories
    if (totalEstimates > 0) {
        allocatedVenue = distributableBudget * (estVenue / totalEstimates);
        allocatedCatering = distributableBudget * (estCatering / totalEstimates);
        allocatedSecurity = distributableBudget * (estSecurity / totalEstimates);
        allocatedEntertainment = distributableBudget * (estEntertainment / totalEstimates);
        allocatedStaffingLogistics = distributableBudget * (estStaffingLogistics / totalEstimates);
    } else {
        // If total estimates are zero (e.g., zero base costs, zero guests), distribute evenly or to a default.
        // For diplomatic events, staffing/logistics is almost always present.
        allocatedStaffingLogistics = distributableBudget;
    }

    // Final sum of all allocations
    const totalAllocated = allocatedVenue + allocatedCatering + allocatedSecurity + allocatedEntertainment + allocatedStaffingLogistics + allocatedCulturalExchange + allocatedContingency;
    remainingBudget = totalBudget - totalAllocated;

    // Ensure no negative allocations due to floating point arithmetic or extreme edge cases
    allocatedVenue = Math.max(0, allocatedVenue);
    allocatedCatering = Math.max(0, allocatedCatering);
    allocatedSecurity = Math.max(0, allocatedSecurity);
    allocatedEntertainment = Math.max(0, allocatedEntertainment);
    allocatedStaffingLogistics = Math.max(0, allocatedStaffingLogistics);
    allocatedCulturalExchange = Math.max(0, allocatedCulturalExchange);
    allocatedContingency = Math.max(0, allocatedContingency);
    remainingBudget = Math.max(0, remainingBudget);

    // Round to 2 decimal places for currency
    const round = (num) => Math.round(num * 100) / 100;

    return {
        allocatedVenue: round(allocatedVenue),
        allocatedCatering: round(allocatedCatering),
        allocatedSecurity: round(allocatedSecurity),
        allocatedEntertainment: round(allocatedEntertainment),
        allocatedStaffingLogistics: round(allocatedStaffingLogistics),
        allocatedCulturalExchange: round(allocatedCulturalExchange),
        allocatedContingency: round(allocatedContingency),
        remainingBudget: round(remainingBudget)
    };
}
